using UnityEngine;
using System.Collections.Generic;

// Generic class for a pool of objects
public class ObjectPool<T> where T : new()
{
    private List<T> pool = new List<T>();
    private int maxSize;

    public ObjectPool(int initialSize, int maxSize)
    {
        this.maxSize = maxSize;

        for (int i = 0; i < initialSize; i++)
        {
            pool.Add(new T());
        }

        Debug.Log("Pool created with " + initialSize + " objects");
    }

    public T Get()
    {
        if (pool.Count > 0)
        {
            T obj = pool[0];
            pool.RemoveAt(0);
            Debug.Log("Object retrieved from pool");
            return obj;
        }

        if (pool.Count < maxSize)
        {
            Debug.Log("Creating new object (pool was empty)");
            return new T();
        }

        Debug.LogWarning("Pool exhausted!");
        return new T();
    }

    public void Return(T obj)
    {
        if (pool.Count < maxSize)
        {
            pool.Add(obj);
            Debug.Log("Object returned to pool");
        }
        else
        {
            Debug.Log("Pool full, discarding object");
        }
    }

    public int Count()
    {
        return pool.Count;
    }
}

// Generic class with multiple type parameters
public class Pair<TKey, TValue>
{
    public TKey Key { get; set; }
    public TValue Value { get; set; }

    public Pair(TKey key, TValue value)
    {
        Key = key;
        Value = value;
    }

    public void Display()
    {
        Debug.Log("Pair: " + Key + " = " + Value);
    }
}

// Generic method
public class Utility
{
    public static T Max<T>(T a, T b) where T : System.IComparable<T>
    {
        return a.CompareTo(b) > 0 ? a : b;
    }

    public static T Min<T>(T a, T b) where T : System.IComparable<T>
    {
        return a.CompareTo(b) < 0 ? a : b;
    }

    public static void Swap<T>(ref T a, ref T b)
    {
        T temp = a;
        a = b;
        b = temp;
    }
}

public class GenericsExample : MonoBehaviour
{
    void Start()
    {
        // Generic class with int
        ObjectPool<int> intPool = new ObjectPool<int>(3, 5);
        intPool.Get();
        intPool.Get();
        intPool.Return(42);

        // Generic class with string
        ObjectPool<string> stringPool = new ObjectPool<string>(2, 4);
        stringPool.Get();
        stringPool.Return("Hello");

        // Pair with multiple types
        Pair<string, int> scorePair = new Pair<string, int>("Hero", 1000);
        scorePair.Display();

        Pair<int, string> levelPair = new Pair<int, string>(5, "Dungeon");
        levelPair.Display();

        // Generic methods
        int maxInt = Utility.Max(10, 20);
        Debug.Log("Max: " + maxInt);

        float minFloat = Utility.Min(3.14f, 2.71f);
        Debug.Log("Min: " + minFloat);

        string a = "Hello";
        string b = "World";
        Utility.Swap(ref a, ref b);
        Debug.Log("a: " + a + ", b: " + b);
    }
}

